1	\chapter{Mayer--Vietoris long exact sequence for sheaf cohomology with $k$-module coefficients}
2	\label{chap:Cohomology_MayerVietoris}
3	
4	This chapter constructs the Mayer--Vietoris long exact sequence for sheaf cohomology valued in $k$-modules, and develops the \v{C}ech-acyclicity machinery for affine basic-open covers. Together these provide the categorical engine for the Serre finiteness argument (Phase~A step~6). The carriers $H^n(X,\mathcal F)$ and $H^{\prime n}(U,\mathcal F)$ live in Chapter~\ref{chap:Cohomology_StructureSheafModuleK} and are imported here.
5	
6	The chapter introduces no protected declarations: every definition, lemma, and instance here is auxiliary, supporting the construction of $H^1(C,\mathcal O_C)$ in Definition~\ref{def:genus}.
7	
8	\section{Functoriality of cohomology in the open variable}
9	\label{sec:hmodule_prime_cohomologyPresheaf}
10	
11	The cohomology-of-an-open carrier $H^{\prime n}(X,\mathcal F)$ is contravariantly functorial in the open variable $X$. Assembling this functoriality yields a presheaf
12	\[
13	  X \longmapsto H^{\prime n}(X, \mathcal F),
14	\]
15	and, varying $\mathcal F$ as well, a bifunctor from sheaves of $k$-modules to presheaves of abelian groups. The codomain is the category of abelian groups because $\Ext$ is always valued there, regardless of the linear enrichment of the source category; the per-fiber $k$-module structure is inherited from the reducible wrapper on $H^{\prime n}$.
16	
17	\begin{definition}\leanok
18	[Cohomology presheaf functor, $H'$ flavor]
19	  \label{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
20	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheafFunctor}
21	  \uses{def:Scheme_HModule_prime, thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
22	  Let $k$ be a field, $C$ a category equipped with a Grothendieck topology $J$, and assume sheafification and $\Ext$ exist for sheaves of $k$-modules on $J$. For $n \in \mathbb N$, define the cohomology presheaf functor
23	  \[
24	    \mathcal H^{\prime n}(k, J) \;:\; \Sheaf\,J\,(\ModuleCat\,k) \longrightarrow (C^{\op} \longrightarrow \AddCommGrpCat)
25	  \]
26	  by the standard composition of the Yoneda embedding, the free-$k$-module functor, sheafification, and the $n$-th $\Ext$ functor.
27	\end{definition}
28	
29	\begin{proof}
30	  \uses{def:Scheme_HModule_prime}
31	  \leanok
32	  The body is a direct categorical composition mirroring the general sheaf-cohomology presheaf functor. Universe pinning is required because the morphism universe of the sheaf category lives one level above the object universe.
33	\end{proof}
34	
35	\begin{definition}\leanok
36	[Cohomology presheaf, $H'$ flavor]
37	  \label{def:Scheme_HModule_prime_cohomologyPresheaf}
38	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheaf}
39	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
40	  In the setting of Definition~\ref{def:Scheme_HModule_prime_cohomologyPresheafFunctor}, let $\mathcal F$ be a sheaf of $k$-modules. For $n \in \mathbb N$, define the cohomology presheaf
41	  \[
42	    \mathcal H^{\prime n}(\mathcal F) \;:\; C^{\op} \longrightarrow \AddCommGrpCat
43	  \]
44	  to be the evaluation of the bifunctor at $\mathcal F$.
45	\end{definition}
46	
47	\begin{proof}
48	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
49	  \leanok
50	  Direct evaluation of the bifunctor at $\mathcal F$.
51	\end{proof}
52	
53	\begin{remark}
54	  For every object $X$ of $C$, the underlying type of $\mathcal H^{\prime n}(\mathcal F)(X)$ is definitionally equal to $H^{\prime n}(X, \mathcal F)$. The per-fiber $k$-module structure is therefore inherited through the $H'$ wrapper.
55	\end{remark}
56	
57	\begin{remark}[Lean implementation]
58	  The cohomology presheaf functor is declared as a non-computable definition and the presheaf as a non-computable abbrev, matching the reducibility conventions of the general sheaf-cohomology API. The abbrev form is load-bearing: downstream definitional unfolding needs to see through to the fiber-level $H'$ carrier.
59	\end{remark}
60	
61	\section{Mayer--Vietoris long exact sequence}
62	\label{sec:hmodule_prime_mayer_vietoris}
63	
64	A Mayer--Vietoris square for a Grothendieck topology $J$ on a category $C$ is a pullback square
65	\[
66	  \begin{tikzcd}
67	    X_1 \ar[r] \ar[d] & X_2 \ar[d] \\
68	    X_3 \ar[r] & X_4
69	  \end{tikzcd}
70	\]
71	that is a $J$-cover: the pair of morphisms $X_2 \to X_4$ and $X_3 \to X_4$ is a covering family, and $X_1$ is the pullback. For a sheaf $\mathcal F$, the cohomology groups of the four corners are linked by a long exact sequence whose building blocks are restriction maps, biproduct maps, and a connecting homomorphism.
72	
73	\subsection{The restriction maps}
74	
75	\begin{definition}\leanok
76	[Sum of two restriction maps]
77	  \label{def:Scheme_HModule_prime_toBiprod}
78	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
79	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
80	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n \in \mathbb N$. Define the morphism
81	  \[
82	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
83	  \]
84	  to be the biproduct lift of the two restriction maps induced by $X_2 \to X_4$ and $X_3 \to X_4$.
85	\end{definition}
86	
87	\begin{proof}
88	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
89	  \leanok
90	  The biproduct exists because the category of abelian groups has finite biproducts. The morphism is built from the contravariant functoriality of the cohomology presheaf.
91	\end{proof}
92	
93	\begin{definition}\leanok
94	[Difference of two restriction maps]
95	  \label{def:Scheme_HModule_prime_fromBiprod}
96	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
97	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
98	  In the same setting, define the morphism
99	  \[
100	    \fromBiprod \;:\; H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F) \longrightarrow H^{\prime n}(X_1, \mathcal F)
101	  \]
102	  to be the biproduct desc of the restriction map $X_1 \to X_2$ and the additive inverse of the restriction map $X_1 \to X_3$.
103	\end{definition}
104	
105	\begin{proof}
106	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
107	  \leanok
108	  The negation is taken in the preadditive morphism group of the codomain category. The sign convention encodes the alternating-sum structure of the \v{C}ech complex.
109	\end{proof}
110	
111	\begin{lemma}\leanok
112	[Composition vanishes]
113	  \label{lem:Scheme_HModule_prime_toBiprod_fromBiprod}
114	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_fromBiprod}
115	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
116	  In the setting above,
117	  \[
118	    \fromBiprod \circ \toBiprod \;=\; 0.
119	  \]
120	\end{lemma}
121	
122	\begin{proof}
123	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
124	  \leanok
125	  This is a formal consequence of the biproduct universal property, preadditivity, and the pullback equation $X_1 \to X_2 \to X_4 = X_1 \to X_3 \to X_4$. Every step is independent of the value category and transfers verbatim from the abelian-group-valued setting.
126	\end{proof}
127	
128	\subsection{The short exact sequence of sheaves}
129	
130	The connecting homomorphism of the Mayer--Vietoris sequence is built from a short exact sequence of sheaves of $k$-modules obtained by sheafifying the Yoneda embedding composed with the free-$k$-module functor.
131	
132	\begin{definition}\leanok
133	[Free-$k$-module functor is left adjoint]
134	  \label{def:Scheme_ModuleCat_free_isLeftAdjoint}
135	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_isLeftAdjoint}
136	  Let $k$ be a field. The free-$k$-module functor $\Type \to \ModuleCat\,k$ is a left adjoint.
137	\end{definition}
138	
139	\begin{proof}
140	  \leanok
141	  The adjunction is the standard free-forgetful adjunction for $k$-modules. The declaration packages the existing adjunction into the typeclass-witness form.
142	\end{proof}
143	
144	\begin{lemma}\leanok
145	[Pushout of free sheaves]
146	  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
147	  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
148	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
149	  Let $S$ be a Mayer--Vietoris square. The image of $S$ under the composite functor
150	  \[
151	    \text{Yoneda} \;\circ\; \text{whiskering with }(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf
152	  \]
153	  is a pushout square in the category of sheaves of $k$-modules.
154	\end{lemma}
155	
156	\begin{proof}
157	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
158	  \leanok
159	  The original square is a pushout. Post-composition with the sheafify-compose functor preserves pushouts because the free-$k$-module functor is a left adjoint. A canonical isomorphism translates the resulting square into the desired shape.
160	\end{proof}
161	
162	\begin{definition}\leanok
163	[Short complex of free sheaves]
164	  \label{def:Scheme_HModule_prime_shortComplex}
165	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
166	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
167	  In the setting of Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}, define the short complex of sheaves of $k$-modules
168	  \[
169	    \mathcal F_1 \xrightarrow{\;f\;} \mathcal F_2 \oplus \mathcal F_3 \xrightarrow{\;g\;} \mathcal F_4,
170	  \]
171	  where $f$ is the biproduct lift of the two maps induced by $X_1 \to X_2$ and $-X_1 \to X_3$, and $g$ is the biproduct desc of the two maps induced by $X_2 \to X_4$ and $X_3 \to X_4$. The composition $g \circ f = 0$ follows from the cokernel-cofork condition of the pushout.
172	\end{definition}
173	
174	\begin{proof}
175	  \uses{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
176	  \leanok
177	  The five object and morphism fields are filled directly from the pushout data; the zero field follows from the cokernel cofork condition.
178	\end{proof}
179	
180	\begin{definition}\leanok
181	[Free-$k$-module functor preserves monomorphisms]
182	  \label{def:Scheme_ModuleCat_free_preservesMonomorphisms}
183	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_preservesMonomorphisms}
184	  Let $k$ be a field. The free-$k$-module functor preserves monomorphisms.
185	\end{definition}
186	
187	\begin{proof}
188	  \leanok
189	  An injective function between types induces an injective $k$-linear map on free modules because the map on finsupp supports is injective. Monomorphism status in the category of $k$-modules is equivalent to injectivity.
190	\end{proof}
191	
192	\begin{lemma}\leanok
193	[The first map is mono]
194	  \label{lem:Scheme_HModule_prime_shortComplex_f_mono}
195	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_f_mono}
196	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
197	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the first map $f$ is a monomorphism.
198	\end{lemma}
199	
200	\begin{proof}
201	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
202	  \leanok
203	  The map $f$ followed by the second projection is the free-$k$-module functor applied to the monomorphism $X_1 \to X_3$, which is mono because the free functor preserves monomorphisms. Hence $f$ itself is mono.
204	\end{proof}
205	
206	\begin{lemma}\leanok
207	[The second map is epi]
208	  \label{lem:Scheme_HModule_prime_shortComplex_g_epi}
209	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_g_epi}
210	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
211	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the second map $g$ is an epimorphism.
212	\end{lemma}
213	
214	\begin{proof}
215	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
216	  \leanok
217	  By the pushout lemma, $g$ is the cokernel of $f$, and every cokernel is epi.
218	\end{proof}
219	
220	\begin{lemma}\leanok
221	[Exactness at the middle term]
222	  \label{lem:Scheme_HModule_prime_shortComplex_exact}
223	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_exact}
224	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
225	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, exactness holds at the middle term: the image of $f$ equals the kernel of $g$.
226	\end{lemma}
227	
228	\begin{proof}
229	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
230	  \leanok
231	  By the pushout lemma, $g$ is the cokernel of $f$; a map is its own kernel's cokernel in an abelian category, so exactness holds at the middle term.
232	\end{proof}
233	
234	\begin{lemma}\leanok
235	[The short complex is short exact]
236	  \label{lem:Scheme_HModule_prime_shortComplex_shortExact}
237	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_shortExact}
238	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
239	  The short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex} is short exact: its first map is mono, its second map is epi, and exactness holds at the middle term.
240	\end{lemma}
241	
242	\begin{proof}
243	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
244	  \leanok
245	  Combine Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_f_mono}, Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_g_epi}, and Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_exact}.
246	\end{proof}
247	
248	\subsection{The connecting homomorphism and the long exact sequence}
249	
250	\begin{definition}\leanok
251	[Connecting homomorphism]
252	  \label{def:Scheme_HModule_prime_delta}
253	  \lean{AlgebraicGeometry.Scheme.HModule'_δ}
254	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, lem:Scheme_HModule_prime_shortComplex_shortExact}
255	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n_0, n_1 \in \mathbb N$ with $n_0 + 1 = n_1$. The connecting homomorphism
256	  \[
257	    \delta \;:\; H^{\prime n_0}(X_1, \mathcal F) \longrightarrow H^{\prime n_1}(X_4, \mathcal F)
258	  \]
259	  is obtained by precomposing the extension class of the short exact sequence of Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_shortExact} with the canonical degree-zero map.
260	\end{definition}
261	
262	\begin{proof}
263	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, lem:Scheme_HModule_prime_shortComplex_shortExact}
264	  \leanok
265	  The extension class lives in $\Ext^1$ of the short exact sequence; precomposing with a map of degree zero and transporting through the additive structure yields the connecting homomorphism as a morphism of abelian groups.
266	\end{proof}
267	
268	\begin{definition}\leanok
269	[Mayer--Vietoris long exact sequence]
270	  \label{def:Scheme_HModule_prime_sequence}
271	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence}
272	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_delta}
273	  In the setting of Definition~\ref{def:Scheme_HModule_prime_delta}, define the five-term Mayer--Vietoris sequence
274	  \[
275	    H^{\prime n_0}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_0}(X_2, \mathcal F) \oplus H^{\prime n_0}(X_3, \mathcal F) \xrightarrow{\;\fromBiprod\;} H^{\prime n_0}(X_1, \mathcal F) \xrightarrow{\;\delta\;} H^{\prime n_1}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_1}(X_2, \mathcal F) \oplus H^{\prime n_1}(X_3, \mathcal F).
276	  \]
277	\end{definition}
278	
279	\begin{proof}
280	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_delta}
281	  \leanok
282	  The sequence is packaged as five composable arrows in the category of abelian groups.
283	\end{proof}
284	
285	\subsection{Comparison with the $\Ext$ contravariant sequence}
286	
287	The following four lemmas bridge the biproduct structure on the abelian-group side with the $\Ext$ biproduct additivity, preparing the comparison isomorphism.
288	
289	\begin{lemma}\leanok
290	[Elementwise formula for $\toBiprod$]
291	  \label{lem:Scheme_HModule_prime_toBiprod_apply}
292	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_apply}
293	  \uses{def:Scheme_HModule_prime_toBiprod}
294	  For $y \in H^{\prime n}(X_4, \mathcal F)$,
295	  \[
296	    \toBiprod(y) \;=\; \bigl(\mathrm{restriction}_{X_4 \to X_2}(y),\; \mathrm{restriction}_{X_4 \to X_3}(y)\bigr).
297	  \]
298	\end{lemma}
299	
300	\begin{proof}
301	  \uses{def:Scheme_HModule_prime_toBiprod}
302	  \leanok
303	  Follows from the definition of $\toBiprod$ as a biproduct lift and the naturality of the biproduct isomorphism with the product.
304	\end{proof}
305	
306	\begin{lemma}\leanok
307	[Elementwise formula for $\fromBiprod$]
308	  \label{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
309	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_biprodIsoProd_inv_apply}
310	  \uses{def:Scheme_HModule_prime_fromBiprod}
311	  For $y_2 \in H^{\prime n}(X_2, \mathcal F)$ and $y_3 \in H^{\prime n}(X_3, \mathcal F)$,
312	  \[
